function classifyConcept(term) {
  const normalized = term.toLowerCase();
  if (normalized.includes("language model") || normalized.includes("llm")) return "foundation-model";
  if (normalized.includes("rag") || normalized.includes("retrieval")) return "application-pattern";
  if (normalized.includes("tool") || normalized.includes("memory") || normalized.includes("planning")) return "agent-capability";
  if (normalized.includes("vector") || normalized.includes("database") || normalized.includes("queue")) return "infrastructure";
  if (normalized.includes("eval") || normalized.includes("score") || normalized.includes("trace")) return "evaluation";
  return "application-pattern";
}
